const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
});

app.use(limiter);
```

---

### 5. 🟠 No CORS Policy (OWASP A05)

**Issue:** With no explicit CORS configuration, Express's default behavior allows cross-origin requests from any browser origin. If this API is ever called from a frontend, malicious sites can make credentialed requests to it.

**Fix:** Explicitly configure [`cors`](https://www.npmjs.com/package/cors) with an allowlist:

```js
const cors = require('cors');

app.use(cors({
  origin: ['https://your-trusted-frontend.com'],
  methods: ['GET'],
  allowedHeaders: ['Authorization', 'Content-Type'],
}));
```

---

